// src/nodes/BaseNode.js
import React from 'react';
import { Handle, Position } from 'reactflow';
import './node.css';

export const BaseNode = ({ 
  id, 
  data,
  title = "Node",
  accentColor = "#3b82f6",
  inputHandles = [],
  outputHandles = [],
  className = "",
  children
}) => {
  return (
    <div className={`vs-node ${className}`} style={{ borderLeft: `4px solid ${accentColor}` }}>
      <div className="vs-node-header">{title}</div>
      <div className="vs-node-body">
        {children}
      </div>
      
      {/* Input Handles */}
      {inputHandles.map((handle, index) => (
        <Handle
          key={`in-${id}-${handle.id || index}`}
          type="target"
          position={handle.position || Position.Left}
          id={handle.id || `input-${index}`}
          style={handle.style || { top: `${30 + index * 25}px` }}
        />
      ))}
      
      {/* Output Handles */}
      {outputHandles.map((handle, index) => (
        <Handle
          key={`out-${id}-${handle.id || index}`}
          type="source"
          position={handle.position || Position.Right}
          id={handle.id || `output-${index}`}
          style={handle.style || { top: `${30 + index * 25}px` }}
        />
      ))}
    </div>
  );
};

// Helper hook for state management
export const useNodeState = (initialData, dataObject) => {
  const [state, setState] = React.useState(initialData);
  
  const updateState = (key, value) => {
    const newState = { ...state, [key]: value };
    setState(newState);
    
    // Update the React Flow data object
    if (dataObject && key in newState) {
      dataObject[key] = value;
    }
  };
  
  return [state, updateState];
};
